import{_ as a,W as t,X as e,Y as d}from"./framework-30063720.js";const i={},r=d('<h2 id="_1-java的特点" tabindex="-1"><a class="header-anchor" href="#_1-java的特点" aria-hidden="true">#</a> 1. Java的特点</h2><ul><li>Java是基于JVM虚拟机的跨平台语言，一次编写，到处运行；</li><li>Java程序易于编写，而且有内置垃圾收集，不必考虑内存管理；</li><li>Java虚拟机拥有工业级的稳定性和高度优化的性能，且经过了长时期的考验；</li><li>Java拥有最广泛的开源社区支持，各种高质量组件随时可用。</li></ul><h2 id="_2-java版本-se、ee、me" tabindex="-1"><a class="header-anchor" href="#_2-java版本-se、ee、me" aria-hidden="true">#</a> 2. Java版本（SE、EE、ME）</h2><p>Java分为三个版本，分别如下：</p><ul><li>Java SE：Standard Edition，标准版</li><li>Java EE：Enterprise Edition，企业版</li><li>Java ME：Micro Edition，瘦身版</li></ul><h3 id="_2-1-不同版本的区别" tabindex="-1"><a class="header-anchor" href="#_2-1-不同版本的区别" aria-hidden="true">#</a> 2.1. 不同版本的区别</h3><table><thead><tr><th>版本</th><th>解析</th></tr></thead><tbody><tr><td>Java SE</td><td>包含标准的JVM和标准库</td></tr><tr><td>Java EE</td><td>在Java SE的基础上加上了大量的API和库，以便方便开发Web应用、数据库、消息服务等，Java EE的应用使用的虚拟机和Java SE完全相同</td></tr><tr><td>Java ME</td><td>针对嵌入式设备的“瘦身版”，Java SE的标准库无法在Java ME上使用，Java ME的虚拟机也是“瘦身版”，不建议学习Java ME</td></tr></tbody></table><h2 id="_3-jdk和jre" tabindex="-1"><a class="header-anchor" href="#_3-jdk和jre" aria-hidden="true">#</a> 3. JDK和JRE</h2><table><thead><tr><th>名词</th><th>完整英文</th><th>解析</th></tr></thead><tbody><tr><td>JDK</td><td>Java Development Kit</td><td>Java源码，要编译成Java字节码，就需要JDK，因为JDK除了包含JRE，还提供了编译器、调试器等开发工具</td></tr><tr><td>JRE</td><td>Java Runtime Environment</td><td>运行Java字节码的虚拟机</td></tr></tbody></table><p>JDK开发Java程序，JRE运行Java程序 JDK=JRE+开发工具 JRE=JVM+核心类库 二者关系如下：</p><figure><img src="https://hk-docs.oss-cn-chengdu.aliyuncs.com/java/JavaBase/1.JavaBase/202304041649172.png" alt="JDK和JRE的关系.png" tabindex="0" loading="lazy"><figcaption>JDK和JRE的关系.png</figcaption></figure><h2 id="_4-安装jdk" tabindex="-1"><a class="header-anchor" href="#_4-安装jdk" aria-hidden="true">#</a> 4. 安装JDK</h2><p>按不同平台自行搜索安装步骤。</p>',13),h=[r];function J(n,l){return t(),e("div",null,h)}const s=a(i,[["render",J],["__file","1.Java-base.html.vue"]]);export{s as default};
